ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  bank_account_detailes: {
    account_status: {
      status: "FAILED",
      statusCode: "409",
      message: "An account already exists with the provided customer details. Please try with new details. If you are a new customer, please validate your information."
    },
    account_data: {
      accountNumber: vars.accountNumber,
      adharNumber: vars.inputAttributes.adharNumber,
      bankName: vars.inputAttributes.bankName,
      ifscCode: vars.ifsc,
      branchName: vars.branchName
    },
    input_data: vars.inputPayload
  }
}

%dw 2.0
output application/json
---
{
	bank_account_detailes: {
		"account_data": {
			"status": "Success",
			"statusCode": 201,
			"message": "Congratulations!, Your account has been created successfully, and an email has been sent to the user.",
			"accountCreatedTimestamp": now(),
			"accountNumber": vars.accountNumber,
			"bankName": vars.inputAttributes.bankName,
			"ifsc_code": vars.ifsc,
			"user_input_data": {
				"data": vars.inputPayload
			}
		}
	}
}
